import { WorkerPoolContextProvider } from "@pierre/diffs/react";
import { useAtomValue } from "jotai";
import type React from "react";

import { useWindowType } from "@/hooks/use-window-type";

import { aWordDiffsEnabled } from "./diff-view-mode";
import { DEFAULT_SHIKI_THEME } from "./shiki-default-theme";

const workerFactory: () => Worker = await loadWorkerFactory();
const SHIKI_WORKER_POOL_SIZE = 4;
const SHIKI_AST_LRU_CACHE_SIZE = 100;

export function ShikiHighlightProvider({
  children,
}: {
  children: React.ReactNode;
}): React.ReactNode {
  const windowType = useWindowType();
  const wordDiffsEnabled = useAtomValue(aWordDiffsEnabled);

  if (windowType !== "electron") {
    // The worker pool doesn't work in VS Code webviews.
    return children;
  }

  return (
    <WorkerPoolContextProvider
      poolOptions={{
        workerFactory,
        poolSize: SHIKI_WORKER_POOL_SIZE,
        totalASTLRUCacheSize: SHIKI_AST_LRU_CACHE_SIZE,
      }}
      highlighterOptions={{
        theme: DEFAULT_SHIKI_THEME,
        lineDiffType: wordDiffsEnabled ? "word-alt" : "none",
        // Optionally preload languages to avoid lazy-loading delays
        langs: ["typescript", "javascript", "css", "html", "python"],
      }}
    >
      {children}
    </WorkerPoolContextProvider>
  );
}

async function loadWorkerFactory(): Promise<() => Worker> {
  if (__STORYBOOK__) {
    const rollupModule = await import("./shiki-worker-factory-rollup");
    return rollupModule.workerFactoryRollup;
  }
  const viteModule = await import("./shiki-worker-factory-vite");
  return viteModule.shikiWorkerFactoryVite;
}
